### 3-1. 사용자 프로필 캐시 (최우선)

파일 위치: `{user-module}/src/main/kotlin/com/maum/backend/service/profile/ProfileService.kt`

```kotlin
// Before: 매 호출마다 DB 조회
@Service
@Transactional(readOnly = true)
class ProfileService(
    private val profileRepository: ProfileRepository,
) {
    fun getProfile(userId: String): ProfileEntity {
        // 매번 SELECT 쿼리 발생
        return profileRepository.findByUserId(userId)
            ?: throw ProfileNotFoundException(userId)
    }
}

// After: Redis 캐시 적용
@Service
@Transactional(readOnly = true)
class ProfileService(
    private val profileRepository: ProfileRepository,
) {
    // 캐시 키: "userProfile::userId:{userId}"
    @Cacheable(
        cacheNames = [CacheNames.USER_PROFILE],
        key = "'userId:' + #userId",
    )
    fun getProfile(userId: String): ProfileCacheDto {
        return profileRepository.findByUserId(userId)
            ?.let { ProfileCacheDto.from(it) }
            ?: throw ProfileNotFoundException(userId)
    }

    // 프로필 수정 시 캐시 무효화
    @CacheEvict(
        cacheNames = [CacheNames.USER_PROFILE],
        key = "'userId:' + #userId",
    )
    @Transactional
    fun updateProfile(userId: String, request: UpdateProfileRequest): ProfileCacheDto {
        val profile = profileRepository.findByUserId(userId)
            ?: throw ProfileNotFoundException(userId)
        // 업데이트 로직...
        return ProfileCacheDto.from(profileRepository.save(profile))
    }
}

// 직렬화 가능한 캐시 전용 DTO (Entity 직접 캐싱 금지)
data class ProfileCacheDto(
    val userId: String,
    val nickname: String,
    val profileImageUrl: String?,
    val bio: String?,
    val age: Int?,
    val gender: String?,
) : Serializable {
