### 3-4. 좋아요 수 카운터 캐시 (집계 쿼리 대체)

파일 위치: `{moment-module}/src/main/kotlin/com/maum/backend/service/like/LikeService.kt`

```kotlin
// Before: 게시물마다 COUNT 집계 쿼리
// SELECT COUNT(*) FROM like WHERE post_id = ? AND status = 1

// After: Redis 카운터 캐시 (RedisTemplate 직접 사용 - 원자성 보장)
@Service
class LikeService(
    private val likeRepository: LikeRepository,
    private val redisTemplate: RedisTemplate<String, Any>,
) {
    private val LIKE_COUNT_PREFIX = "${CacheNames.POST_LIKE_COUNT}::"

    // 좋아요 수 조회: Redis 우선, 미스 시 DB 조회 후 캐시 저장
    fun getLikeCount(postId: String): Long {
        val key = "$LIKE_COUNT_PREFIX$postId"
        val cached = redisTemplate.opsForValue().get(key)
        if (cached != null) return cached.toString().toLong()

        val count = likeRepository.countByPostIdAndStatus(postId, 1)
        redisTemplate.opsForValue().set(key, count, Duration.ofMinutes(5))
        return count
    }

    // 좋아요 추가: DB 저장 + Redis INCR (원자적)
    @Transactional
    fun like(userId: String, postId: String) {
        likeRepository.save(LikeEntity(userId = userId, postId = postId, status = 1))
        val key = "$LIKE_COUNT_PREFIX$postId"
        // 캐시가 존재하면 증가, 없으면 초기화하지 않음 (다음 조회 시 DB에서 로드)
        if (redisTemplate.hasKey(key) == true) {
            redisTemplate.opsForValue().increment(key)
        }
    }

    // 좋아요 취소: DB 수정 + Redis DECR
    @Transactional
    fun unlike(userId: String, postId: String) {
        likeRepository.updateStatus(userId, postId, 0)
        val key = "$LIKE_COUNT_PREFIX$postId"
        if (redisTemplate.hasKey(key) == true) {
            redisTemplate.opsForValue().decrement(key)
        }
    }
}
```

